import{_ as i,r as s,o as n,c,a as t,b as e,e as a,d as r}from"./app-2671d5e3.js";const l={},m=t("h1",{id:"how-to-segment-the-audience-by-the-social-login-provider",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#how-to-segment-the-audience-by-the-social-login-provider","aria-hidden":"true"},"#"),e(" How to segment the audience by the social login provider")],-1),h=t("p",null,"This article explains how to configure fields and connections to add social login provider information into the MailChimp audience contact.",-1),p={href:"/docs-v3/um-social-login/article/82-mailchimp-setup",target:"_blank",rel:"noopener noreferrer"},d={href:"https://ultimatemember.com/extensions/mailchimp/",target:"_blank",rel:"noopener noreferrer"},u={href:"/docs-v3/um-social-login/article/1531-social-login-2-3-setup",target:"_blank",rel:"noopener noreferrer"},g={href:"https://ultimatemember.com/extensions/social-login/",target:"_blank",rel:"noopener noreferrer"},f=r('<p>The extension &quot;Ultimate Member - Social Login&quot; saves social provider information in the usermeta with the meta key like &quot;_uid_{provider}&quot;. You may use these usermeta to get data for the MailChimp audience.</p><p>1) Create text fields in the form builder with proper meta keys. Example:</p><ul><li>_uid_facebook</li><li>_uid_google</li><li>_uid_linkedin</li></ul><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/5f1ec79204286306f8076cb3/file-PDQM9Xo03t.png" alt=""></p><p><strong>Note:</strong> You may remove these fields from the form if you don&#39;t need them there, but don&#39;t delete them from the &quot;Fields Manager&quot;.</p><p>2) Create the same fields in the MailChimp audience.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/5f1ec79e04286306f8076cb4/file-HS2CHbeTXO.png" alt=""></p><p>3) Configure fields relationship in the MailChimp connection on the page [wp-admin &gt; Ultimate Member &gt; MailChimp &gt; Edit].</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/5f1ec7a92c7d3a10cbab56eb/file-S1U3Wve4mi.png" alt=""></p><p>4) Run the tool &quot;Sync Profiles&quot; on the page [wp-admin &gt; Ultimate Member &gt; Dashboard]. You may use slow version to see details.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/5f1ec7b304286306f8076cb6/file-bf9Jeyzsht.png" alt=""></p><p>5) Look at the MailChimp audience members. You should see social UID in the fields.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/5f1ec7e52c7d3a10cbab56f0/file-j3dt4rbgh5.png" alt=""></p><p>6) You can use these fields to segment the audience by the social provider.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/5f1ec7ef2c7d3a10cbab56f1/file-BdYln2WV3a.png" alt=""></p>',15);function b(_,w){const o=s("ExternalLinkIcon");return n(),c("div",null,[m,h,t("p",null,[e('Read the article " '),t("a",p,[e("MailChimp Setup"),a(o)]),e(' " to get know basic information about extension " '),t("a",d,[e("Ultimate Member - MailChimp"),a(o)]),e(' ". Read the article " '),t("a",u,[e("Social Login 2.3 Setup"),a(o)]),e(' " to get know basic information about extension " '),t("a",g,[e("Ultimate Member - Social Login"),a(o)]),e(' ".')]),f])}const k=i(l,[["render",b],["__file","1572-how-to-segment-the-audience-by-the-social-login-provider.html.vue"]]);export{k as default};
